import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"梦魇靴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/梦魇靴.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/梦魇靴.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/梦魇靴.md"};function l(_,a,i,p,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"梦魇靴",tabindex:"-1"},[s("梦魇靴 "),e("a",{class:"header-anchor",href:"#梦魇靴","aria-label":'Permalink to "梦魇靴"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="梦魇靴-1" tabindex="-1">梦魇靴 <a class="header-anchor" href="#梦魇靴-1" aria-label="Permalink to &quot;梦魇靴&quot;">​</a></h1><p>梦魇靴<br> 位置：脚部 <br> 价格：C+1250<br> 这双被邪恶战士珍藏的靴子，由漆黑的皮革修剪制成，附有深红色的梦魇鬃毛。害怕梦魇的人，会在看到这深红的鬃毛时回忆起梦魇的恐怖。<br> 武器伤害：2L+3附加成功<br> 专业：腿<br> 分类：肉搏武器<br> 占据：鞋袜位<br> 体积：1<br> 视为天生武器般使用腿专业，伤害由冲击转化为严重<br> 具有【引火长径】特性。</p><p>引火长径：<br> 当穿戴者进行一次近战肉搏冲锋时，火焰与浓烟从将靴子中涌出，点燃穿戴者通行过的路径，这些魔法火焰可以在任意平面燃烧，包括且不限于水面，冰雪以及飞船的隔热装甲，这会令这一次冲锋攻击同时对路径范围上的所有敌方单位均造成影响，且这一次冲锋攻击造成的伤害转化为火焰伤害。<br> 引火长径的魔法可以燃烧6秒，随后无害的消散（但也可能如正常火焰般点燃什么，ST决定），若有单位在火焰尚未熄灭时踏入其中，其会如同被这次冲锋攻击影响到一般受到伤害，也就是说一个单位不会因此多次受到同一次冲锋的伤害。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
